                        response = Response.FromValue(ResolverContractData.FromResponse(result), result);
                        break;
                    case 404:
                        response = Response.FromValue((ResolverContractData)null, result);
                        break;
                    default:
                        throw new RequestFailedException(result);
                }
                if (response.Value == null)
                {
                    return new NoValueResponse<ResolverContractResource>(response.GetRawResponse());
                }
                return Response.FromValue(new ResolverContractResource(Client, response.Value), response.GetRawResponse());
            }
            catch (Exception e)
            {
                scope.Failed(e);
                throw;
            }
        }

        IEnumerator<ResolverContractResource> IEnumerable<ResolverContractResource>.GetEnumerator()
        {
            return GetAll().GetEnumerator();
        }

